{"path": "/tmp/sv-ff0f0ef7471f47a1b2baee94d336be93/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "
@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage - 1))" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>
            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(page))">@page</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage + 1))" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int CurrentPage { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        // Show up to 7 page numbers centered around the current page
        const int maxVisible = 7;
        int start = Math.Max(1, CurrentPage - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}
"}

{"path": "/tmp/sv-ff0f0ef7471f47a1b2baee94d336be93/Components/Pages/Catalog/Catalog.razor", "file_text": "
@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-3 mb-3">
            <CatalogSidebar Categories="_categories"
                            OnFiltersApplied="HandleFiltersApplied" />
        </div>
        <div class="col-lg-9">
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products...</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_totalCount"
                                Page="_currentPage"
                                PageSize="PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_products"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> _products = [];
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = categoriesTask.Result;
            ApplySearchResult(searchTask.Result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire up cart service when available
        return Task.CompletedTask;
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            ApplySearchResult(result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplySearchResult(PagedResult<Product> result)
    {
        _products = result.Items;
        _totalCount = result.TotalCount;
        _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
    }

    private async Task RetryLoad()
    {
        _error = null;
        _loading = true;
        await LoadProducts();
    }
}
"}

